import React from "react";

export default function TextFrom(props) {
  return (
    <>
      <form>
        <div className="container">
            <h1>{props.heading}</h1>
          <div class="form-group">
            <label for="myBox">Example textarea</label>
            <textarea class="form-control" id="myBox" rows="3"></textarea>
          </div>
        </div>
      </form>
    </>
  );
}
